sql:
SELECT COUNT(DISTINCT user_id) AS unique_users_count
FROM events
WHERE app_id = 1;

SELECT COUNT(DISTINCT up.user_id) AS unique_user_count
FROM user_profiles up
WHERE up.app_id = 123;

external_knowledge:
; 'Most active users' refers to the users with the highest number of events; 
; The number of events for each user is calculated by grouping the events table by user ID and counting the number of events; 
; The results are ranked within each application by the event count in descending order.
